// ── Nav ───────────────────────────────────────────────────────────────────────
function NetflixNav({ active, setActive }) {
  const [scrolled, setScrolled] = useState(false);
  useEffect(() => {
    const h = () => setScrolled(window.scrollY > 20);
    window.addEventListener("scroll", h);
    return () => window.removeEventListener("scroll", h);
  }, []);

  return (
    <nav style={{
      position: "fixed", top: 0, left: 0, right: 0, zIndex: 200,
      display: "flex", justifyContent: "space-between", alignItems: "center",
      padding: "14px 48px",
      background: scrolled ? "#141414" : "linear-gradient(to bottom, rgba(0,0,0,0.85) 0%, transparent 100%)",
      transition: "background 0.3s",
    }}>
      {/* Logo */}
      <button onClick={() => setActive("home")} style={{
        background: "none", border: "none", cursor: "pointer",
        fontFamily: "'Arial Black', Arial, sans-serif",
        fontSize: 28, fontWeight: 900, letterSpacing: -1,
        color: "#e50914", textTransform: "uppercase",
      }}>
        PhaniK
      </button>

      {/* Nav links */}
      <div style={{ display: "flex", gap: 28 }}>
        {["home", "experience", "skills", "contact"].map(item => (
          <button key={item} onClick={() => setActive(item)} style={{
            background: "none", border: "none", cursor: "pointer",
            fontFamily: "Arial, sans-serif", fontSize: 13, fontWeight: active === item ? 700 : 400,
            letterSpacing: 1, textTransform: "uppercase",
            color: active === item ? "#fff" : "rgba(255,255,255,0.6)",
            transition: "color 0.2s",
            borderBottom: active === item ? "2px solid #e50914" : "2px solid transparent",
            paddingBottom: 2,
          }}>{item}</button>
        ))}
      </div>
    </nav>
  );
}

