// ── Experience ─────────────────────────────────────────────────────────────────
function SkillPill({ label }) {
  return (
    <span style={{
      fontFamily: "Arial, sans-serif", fontSize: 12,
      background: "rgba(229,9,20,0.15)",
      color: "#e50914", border: "1px solid rgba(229,9,20,0.3)",
      padding: "3px 10px", borderRadius: 2, whiteSpace: "nowrap",
    }}>{label}</span>
  );
}

function ExpCard({ item, isOpen, onClick }) {
  return (
    <div
      onClick={onClick}
      style={{
        background: isOpen ? "#1f1f1f" : "#181818",
        border: `1px solid ${isOpen ? "#e50914" : "rgba(255,255,255,0.07)"}`,
        borderRadius: 6, cursor: "pointer",
        transition: "all 0.25s",
        overflow: "hidden",
        transform: isOpen ? "scale(1)" : "scale(1)",
      }}
      onMouseOver={e => { if (!isOpen) e.currentTarget.style.border = "1px solid rgba(255,255,255,0.2)"; }}
      onMouseOut={e => { if (!isOpen) e.currentTarget.style.border = "1px solid rgba(255,255,255,0.07)"; }}
    >
      {/* Card header */}
      <div style={{ padding: "24px 28px" }}>
        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start" }}>
          <div>
            <div style={{ fontFamily: "Arial, sans-serif", fontSize: 11, color: "#e50914", letterSpacing: 2, marginBottom: 6, textTransform: "uppercase" }}>
              {item.period}
            </div>
            <h3 style={{ fontFamily: "'Arial Black', sans-serif", fontSize: 20, color: "#fff", fontWeight: 900, margin: "0 0 4px" }}>
              {item.company}
            </h3>
            <p style={{ fontFamily: "Arial, sans-serif", fontSize: 13, color: "rgba(255,255,255,0.5)", margin: 0 }}>
              {item.role} · {item.location}
            </p>
          </div>
          <div style={{
            width: 32, height: 32, borderRadius: "50%",
            background: isOpen ? "#e50914" : "rgba(255,255,255,0.1)",
            display: "flex", alignItems: "center", justifyContent: "center",
            color: "#fff", fontSize: 16, flexShrink: 0, transition: "all 0.2s",
            transform: isOpen ? "rotate(180deg)" : "rotate(0deg)",
          }}>▾</div>
        </div>
        <div style={{ display: "flex", gap: 8, flexWrap: "wrap", marginTop: 14 }}>
          {item.tags.map(t => <SkillPill key={t} label={t} />)}
        </div>
      </div>
      {/* Expandable highlights */}
      {isOpen && (
        <div style={{
          padding: "0 28px 24px",
          borderTop: "1px solid rgba(255,255,255,0.07)",
        }}>
          <ul style={{ listStyle: "none", padding: 0, margin: "16px 0 0" }}>
            {item.highlights.map((h, i) => (
              <li key={i} style={{ display: "flex", gap: 12, marginBottom: 12 }}>
                <span style={{ color: "#e50914", fontSize: 14, flexShrink: 0, marginTop: 1 }}>▸</span>
                <span style={{ fontFamily: "Arial, sans-serif", fontSize: 13, color: "rgba(255,255,255,0.65)", lineHeight: 1.7 }}>{h}</span>
              </li>
            ))}
          </ul>
        </div>
      )}
    </div>
  );
}

