// ── Skills ────────────────────────────────────────────────────────────────────
function HScrollRow({ category, items }) {
  const ref = useRef(null);
  const [hovered, setHovered] = useState(false);

  return (
    <div style={{ marginBottom: 40 }}>
      <h3 style={{
        fontFamily: "Arial, sans-serif", fontSize: 15, fontWeight: 700,
        color: "rgba(255,255,255,0.7)", marginBottom: 14,
        letterSpacing: 0.5,
      }}>{category}</h3>
      <div style={{ position: "relative" }}>
        <div
          ref={ref}
          style={{
            display: "flex", gap: 10, overflowX: "auto", paddingBottom: 8,
            scrollbarWidth: "none",
            msOverflowStyle: "none",
          }}
        >
          {items.map(item => (
            <div key={item}
              onMouseEnter={() => setHovered(item)}
              onMouseLeave={() => setHovered(null)}
              style={{
                flexShrink: 0,
                background: hovered === item ? "#e50914" : "#1f1f1f",
                border: `1px solid ${hovered === item ? "#e50914" : "rgba(255,255,255,0.1)"}`,
                borderRadius: 4, padding: "10px 18px",
                fontFamily: "Arial, sans-serif", fontSize: 13,
                color: hovered === item ? "#fff" : "rgba(255,255,255,0.7)",
                cursor: "default", transition: "all 0.18s",
                transform: hovered === item ? "scale(1.06)" : "scale(1)",
              }}>
              {item}
            </div>
          ))}
        </div>
      </div>
    </div>
  );
}

